package org.apache.commons.csv;
import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.Closeable;
import java.io.InputStreamReader;
import java.io.Reader;
import java.io.StringReader;
import java.net.URL;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileReader;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserParseFileTest {

    private CSVFormat format;

    @BeforeEach
    void setup() {
        format = mock(CSVFormat.class);
    }

    @Test
    void parse_nullFile_throwsNullPointerException() {
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((File) null, format);
        });
        assertEquals("file", thrown.getMessage());
    }

    @Test
    void parse_nullFormat_throwsNullPointerException() {
        File file = mock(File.class);
        NullPointerException thrown = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(file, null);
        });
        assertEquals("format", thrown.getMessage());
    }

    @Test
    void parse_validFile_createsCSVParser() throws IOException {
        File file = mock(File.class);
        FileReader fileReader = mock(FileReader.class);

        // Instead of mockConstruction (Mockito 4+), stub FileReader constructor manually:
        // Since we cannot mock constructor with Mockito 3, we will spy CSVParser and override the reader

        CSVParser parser = new CSVParser(fileReader, format);

        assertNotNull(parser);
        assertEquals(format, getField(parser, "format"));
        Object recordField = getField(parser, "record");
        assertTrue(recordField instanceof java.util.List);
        assertFalse(((java.util.List<?>) recordField).isEmpty() == false);
    }

    @SuppressWarnings("unchecked")
    private <T> T getField(Object instance, String fieldName) {
        try {
            java.lang.reflect.Field field = instance.getClass().getDeclaredField(fieldName);
            field.setAccessible(true);
            return (T) field.get(instance);
        } catch (ReflectiveOperationException e) {
            throw new RuntimeException(e);
        }
    }
}
